// very important, if you don't know what it is, don't touch it
// 非常重要，不懂代码不要动，这里可以解决80%的问题，也可以生产1000+的bug
const hookClick = (e) => {
    const origin = e.target.closest('a')
    const isBaseTargetBlank = document.querySelector(
        'head base[target="_blank"]'
    )

    if (!origin || !origin.href) {
        return
    }

    // 处理 download 属性（数据导出）
    if (origin.hasAttribute('download')) {
        e.preventDefault()
        console.log('handle download', origin.href, origin.download)
        // 手动触发下载
        const a = document.createElement('a')
        a.href = origin.href
        a.download = origin.download || ''
        a.style.display = 'none'
        document.body.appendChild(a)
        a.click()
        document.body.removeChild(a)
        return
    }

    // 处理 Blob URL（PDF/JSON 导出）
    if (origin.href.startsWith('blob:')) {
        e.preventDefault()
        console.log('handle blob download', origin.href)
        // 手动触发下载
        const a = document.createElement('a')
        a.href = origin.href
        a.download = ''
        a.style.display = 'none'
        document.body.appendChild(a)
        a.click()
        document.body.removeChild(a)
        return
    }

    // 原有的 target="_blank" 处理
    if (
        (origin && origin.href && origin.target === '_blank') ||
        (origin && origin.href && isBaseTargetBlank)
    ) {
        e.preventDefault()
        console.log('handle origin', origin)
        location.href = origin.href
    }
}

window.open = function (url, target, features) {
    console.log('open', url, target, features)
    // Blob URL 不通过 location.href 跳转，改为触发下载
    if (url && url.startsWith('blob:')) {
        const a = document.createElement('a')
        a.href = url
        a.download = ''
        a.style.display = 'none'
        document.body.appendChild(a)
        a.click()
        document.body.removeChild(a)
        return null
    }
    location.href = url
}

document.addEventListener('click', hookClick, { capture: true })
